const emails = $input.all().map(i => {
  const m = i.json;
  const fromAddr = m.from?.emailAddress?.address || '';
  const fromName = m.from?.emailAddress?.name || fromAddr;
  const storeMatch = fromAddr.match(/^([A-Z]{2}\d{2,3})\.sm@/i);
  const storeCode  = storeMatch ? storeMatch[1].toUpperCase() : null;
  const body = (m.body?.content || m.bodyPreview || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  return {
    id:           m.id,
    subject:      m.subject || '(No subject)',
    fromAddr,
    fromName,
    storeCode,
    receivedAt:   m.receivedDateTime,
    bodyPreview:  body.slice(0, 200),
    body:         body.slice(0, 3000),
    hasStoreCode: !!storeCode,
  };
});
return [{ json: { success: true, count: emails.length, emails } }];

const body = $input.first().json.body || {};
const templates = body.templates || [];

const templateSummary = templates.map(t => {
  const cleanBody = t.body
    .replace(/<table[^>]*>[\s\S]*?<\/table>/gi, '[TABLE FORMAT REQUIRED]')
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  return `ID ${t.id}: ${t.name} (${t.category})\n${cleanBody}`;
}).join('\n---\n');

return [{ json: { body, templateSummary: templateSummary.slice(0, 6000), templates } }];

const raw = $input.first().json;
const content = raw?.choices?.[0]?.message?.content || '{}';
let parsed = {};
try { parsed = JSON.parse(content); } catch { parsed = { description: content, missingFromTemplate: [], suggestedReply: '', isComplete: false }; }
return [{ json: { success: true, ...parsed } }];

const b = $('Webhook - POST /vmm-send-email-reply').first().json.body || {};

const rawHtml = b.htmlBody || (b.body ? b.body.split('\n').map(l => l.trim() ? `<p style="margin:0 0 8px">${l}</p>` : '<br/>').join('') : '');

const htmlBody = rawHtml
  + '<hr style="margin:16px 0;border:none;border-top:1px solid #e2e8f0"/>'
  + '<p style="font-size:11px;color:#64748b">VMM CRM — Open Mind Services Limited</p>';

return [{ json: { messageId: b.messageId || '', htmlBody } }];

const templates = $input.all()
  .map(i => ({
    id:       parseInt(i.json['ID'] || 0),
    name:     i.json['Template Name'] || '',
    category: i.json['Category']      || '',
    body:     i.json['Template Body'] || '',
  }))
  .filter(t => t.id > 0 && t.name);
return [{ json: { success: true, count: templates.length, templates } }];
